ALGORITHM MatrixMultiplyTiled(A, B, C, N, TILE_SIZE)
// A, B: input matrices of size N x N
// C: output matrix of size N x N
// TILE_SIZE: size of the tile (block) for shared memory

INPUT: Matrices A, B, C, dimension N, tile size TILE_SIZE
OUTPUT: Matrix C containing A × B

BEGIN
 // Declare shared memory tiles
 DECLARE shared_A[TILE_SIZE][TILE_SIZE]
 DECLARE shared_B[TILE_SIZE][TILE_SIZE]

 // Get thread and block indices
 row = blockIdx.y * TILE_SIZE + threadIdx.y
 col = blockIdx.x * TILE_SIZE + threadIdx.x

 // Each thread computes one element of C
 sum = 0

 // Loop over all tiles of A and B
 FOR tile = 0 TO (N / TILE_SIZE) - 1 DO

 // COALESCED LOAD: Threads collaboratively load tile of A
 // Thread (i, j) loads A[row][tile*TILE_SIZE + j]
 shared_A[threadIdx.y][threadIdx.x] = A[row][tile * TILE_SIZE + threadIdx.x]

 // COALESCED LOAD: Threads collaboratively load tile of B
 // Thread (i, j) loads B[tile*TILE_SIZE + i][col]
 shared_B[threadIdx.y][threadIdx.x] = B[tile * TILE_SIZE + threadIdx.y][col]

 // Synchronize all threads in block to ensure data is loaded
 SYNC

 // Compute partial result using shared memory (fast access)
 FOR k = 0 TO TILE_SIZE - 1 DO
 sum = sum + shared_A[threadIdx.y][k] * shared_B[k][threadIdx.x]
 END FOR

 // Synchronize before loading next tile
 SYNC
 END FOR

 // Write result to global memory
 C[row][col] = sum

END

/*
 * GPU Matrix Multiplication with Shared Memory Tiling
 * Demonstrates key GPU performance optimization techniques:
 * - Coalesced global memory access
 * - Shared memory for data reuse
 * - Warp-synchronous execution
 * - Occupancy optimization
 */

#include <stdio.h>
#include <stdlib.h>
#include <cuda_runtime.h>

#define TILE_SIZE 16
#define N 1024

// Check for CUDA errors
#define CUDA_CHECK(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 printf("CUDA error at %s:%d: %s\n", __FILE__, __LINE__, \
 cudaGetErrorString(err)); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

/*
 * Optimized Matrix Multiplication Kernel
 * Uses shared memory tiling to reduce global memory accesses
 * 
 * Performance optimizations:
 * 1. Coalesced memory access - consecutive threads access consecutive addresses
 * 2. Shared memory caching - fast on-chip memory for tile storage
 * 3. Register usage optimization - minimal local variables
 */
__global__ void matrixMultiplyTiled(float* A, float* B, float* C, int n) {
 // Shared memory declaration - fast on-chip memory per SM
 __shared__ float tileA[TILE_SIZE][TILE_SIZE];
 __shared__ float tileB[TILE_SIZE][TILE_SIZE];

 // Calculate row and column of C to compute
 int row = blockIdx.y * TILE_SIZE + threadIdx.y;
 int col = blockIdx.x * TILE_SIZE + threadIdx.x;

 // Thread index within the tile
 int tx = threadIdx.x;
 int ty = threadIdx.y;

 // Accumulator for dot product
 float sum = 0.0f;

 // Number of tiles needed to cover matrices
 int numTiles = (n + TILE_SIZE - 1) / TILE_SIZE;

 // Loop over all tiles
 for (int tile = 0; tile < numTiles; tile++) {
 // COALESCED LOAD: Load tile from matrix A into shared memory
 // Each thread loads one element
 // Consecutive threads load consecutive global memory locations
 int aCol = tile * TILE_SIZE + tx;
 if (row < n && aCol < n) {
 tileA[ty][tx] = A[row * n + aCol];
 } else {
 tileA[ty][tx] = 0.0f;
 }

 // COALESCED LOAD: Load tile from matrix B into shared memory
 int bRow = tile * TILE_SIZE + ty;
 if (bRow < n && col < n) {
 tileB[ty][tx] = B[bRow * n + col];
 } else {
 tileB[ty][tx] = 0.0f;
 }

 // Synchronize: ensure all threads in block have loaded tiles
 __syncthreads();

 // Compute partial dot product using shared memory (fast access)
 // This is much faster than accessing global memory repeatedly
 for (int k = 0; k < TILE_SIZE; k++) {
 sum += tileA[ty][k] * tileB[k][tx];
 }

 // Synchronize: ensure computation is done before loading next tile
 __syncthreads();
 }

 // Write result to global memory
 if (row < n && col < n) {
 C[row * n + col] = sum;
 }
}

/*
 * Naive Matrix Multiplication (for comparison)
 * Each thread independently reads entire row from A and column from B
 * Results in uncoalesced access and redundant global memory reads
 */
__global__ void matrixMultiplyNaive(float* A, float* B, float* C, int n) {
 int row = blockIdx.y * blockDim.y + threadIdx.y;
 int col = blockIdx.x * blockDim.x + threadIdx.x;

 if (row < n && col < n) {
 float sum = 0.0f;
 for (int k = 0; k < n; k++) {
 // Non-coalesced access: threads in same warp access
 // strided locations in global memory
 sum += A[row * n + k] * B[k * n + col];
 }
 C[row * n + col] = sum;
 }
}

int main() {
 // Allocate host memory
 float *h_A = (float*)malloc(N * N * sizeof(float));
 float *h_B = (float*)malloc(N * N * sizeof(float));
 float *h_C = (float*)malloc(N * N * sizeof(float));

 // Initialize matrices with random data
 for (int i = 0; i < N * N; i++) {
 h_A[i] = rand() / (float)RAND_MAX;
 h_B[i] = rand() / (float)RAND_MAX;
 }

 // Allocate device memory
 float *d_A, *d_B, *d_C;
 CUDA_CHECK(cudaMalloc(&d_A, N * N * sizeof(float)));
 CUDA_CHECK(cudaMalloc(&d_B, N * N * sizeof(float)));
 CUDA_CHECK(cudaMalloc(&d_C, N * N * sizeof(float)));

 // Copy data from host to device
 CUDA_CHECK(cudaMemcpy(d_A, h_A, N * N * sizeof(float), cudaMemcpyHostToDevice));
 CUDA_CHECK(cudaMemcpy(d_B, h_B, N * N * sizeof(float), cudaMemcpyHostToDevice));

 // Configure kernel launch parameters
 // Occupancy optimization: use enough blocks to keep all SMs busy
 dim3 threads(TILE_SIZE, TILE_SIZE, 1);
 dim3 blocks((N + TILE_SIZE - 1) / TILE_SIZE, 
 (N + TILE_SIZE - 1) / TILE_SIZE, 1);

 printf("Matrix size: %d x %d\n", N, N);
 printf("Threads per block: %d x %d = %d\n", TILE_SIZE, TILE_SIZE, TILE_SIZE*TILE_SIZE);
 printf("Blocks per grid: %d x %d = %d\n", blocks.x, blocks.y, blocks.x*blocks.y);

 // Create CUDA events for timing
 cudaEvent_t start, stop;
 CUDA_CHECK(cudaEventCreate(&start));
 CUDA_CHECK(cudaEventCreate(&stop));

 // Launch optimized tiled kernel
 CUDA_CHECK(cudaEventRecord(start));
 matrixMultiplyTiled<<<blocks, threads>>>(d_A, d_B, d_C, N);
 CUDA_CHECK(cudaEventRecord(stop));
 CUDA_CHECK(cudaEventSynchronize(stop));

 float milliseconds = 0;
 CUDA_CHECK(cudaEventElapsedTime(&milliseconds, start, stop));
 printf("\nOptimized kernel (tiled) execution time: %.2f ms\n", milliseconds);

 // Copy result back to host
 CUDA_CHECK(cudaMemcpy(h_C, d_C, N * N * sizeof(float), cudaMemcpyDeviceToHost));

 // Free device memory
 CUDA_CHECK(cudaFree(d_A));
 CUDA_CHECK(cudaFree(d_B));
 CUDA_CHECK(cudaFree(d_C));

 // Free host memory
 free(h_A);
 free(h_B);
 free(h_C);

 printf("Matrix multiplication completed successfully!\n");

 return 0;
}
